local function xbcgFYUNItVdWIeM(a, b)
    local p, c = 1, 0
    while a > 0 and b > 0 do
        local ra, rb = a % 2, b % 2
        if ra ~= rb then c = c + p end
        a, b, p = math.floor((a - ra) / 2), math.floor((b - rb) / 2), p * 2
    end
    if a < b then a = b end
    while a > 0 do
        local ra = a % 2
        if ra > 0 then c = c + p end
        a, p = math.floor((a - ra) / 2), p * 2
    end
    return c
end

